import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"脉诊速查","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/06-跨病证索引/08-脉诊速查.md","filePath":"tcm-data/06-跨病证索引/08-脉诊速查.md","lastUpdated":1781084559000}'),r={name:"tcm-data/06-跨病证索引/08-脉诊速查.md"};function n(s,t,i,g,o,x){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="脉诊速查" tabindex="-1">脉诊速查 <a class="header-anchor" href="#脉诊速查" aria-label="Permalink to &quot;脉诊速查&quot;">​</a></h1><blockquote><p>28种脉象速查，附病机对应与方剂参考</p></blockquote><hr><h2 id="一、28种脉象分类" tabindex="-1">一、28种脉象分类 <a class="header-anchor" href="#一、28种脉象分类" aria-label="Permalink to &quot;一、28种脉象分类&quot;">​</a></h2><h3 id="按部位分类" tabindex="-1">按部位分类 <a class="header-anchor" href="#按部位分类" aria-label="Permalink to &quot;按部位分类&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">分类</th><th style="text-align:left;">脉象</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>浮脉类</strong>（轻取即得）</td><td style="text-align:left;">浮、洪、濡、散、芤、革</td><td style="text-align:left;">表证、虚阳外浮</td></tr><tr><td style="text-align:left;"><strong>沉脉类</strong>（重按始得）</td><td style="text-align:left;">沉、伏、弱、牢</td><td style="text-align:left;">里证、寒湿内伏</td></tr><tr><td style="text-align:left;"><strong>迟脉类</strong>（一息不足四至）</td><td style="text-align:left;">迟、缓、涩、结</td><td style="text-align:left;">寒证、阳虚</td></tr><tr><td style="text-align:left;"><strong>数脉类</strong>（一息五至以上）</td><td style="text-align:left;">数、促、动</td><td style="text-align:left;">热证、虚阳上浮</td></tr><tr><td style="text-align:left;"><strong>虚脉类</strong>（应指无力）</td><td style="text-align:left;">虚、微、细、代、短</td><td style="text-align:left;">气血不足</td></tr><tr><td style="text-align:left;"><strong>实脉类</strong>（应指有力）</td><td style="text-align:left;">实、滑、紧、长、弦</td><td style="text-align:left;">邪气壅盛</td></tr></tbody></table><hr><h2 id="二、常见脉象详解" tabindex="-1">二、常见脉象详解 <a class="header-anchor" href="#二、常见脉象详解" aria-label="Permalink to &quot;二、常见脉象详解&quot;">​</a></h2><h3 id="浮脉" tabindex="-1">浮脉 <a class="header-anchor" href="#浮脉" aria-label="Permalink to &quot;浮脉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉象</strong></td><td style="text-align:left;">轻取即得，重按反减</td></tr><tr><td style="text-align:left;"><strong>主病</strong></td><td style="text-align:left;">表证（感冒初期）、虚阳外浮</td></tr><tr><td style="text-align:left;"><strong>相关</strong></td><td style="text-align:left;">如果脉浮→可能相火上逆</td></tr><tr><td style="text-align:left;"><strong>方剂参考</strong></td><td style="text-align:left;">浮紧→麻黄汤；浮缓→桂枝汤</td></tr></tbody></table><h3 id="沉脉" tabindex="-1">沉脉 <a class="header-anchor" href="#沉脉" aria-label="Permalink to &quot;沉脉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉象</strong></td><td style="text-align:left;">轻取不应，重按始得</td></tr><tr><td style="text-align:left;"><strong>主病</strong></td><td style="text-align:left;">里证（病在脏腑）、寒湿内伏</td></tr><tr><td style="text-align:left;"><strong>相关</strong></td><td style="text-align:left;">⭐ <strong>很可能沉脉</strong>（水寒土湿）</td></tr><tr><td style="text-align:left;"><strong>方剂参考</strong></td><td style="text-align:left;">沉迟→四逆汤；沉弦→四逆散</td></tr></tbody></table><h3 id="迟脉" tabindex="-1">迟脉 <a class="header-anchor" href="#迟脉" aria-label="Permalink to &quot;迟脉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉象</strong></td><td style="text-align:left;">一息不足四至（&lt;60次/分）</td></tr><tr><td style="text-align:left;"><strong>主病</strong></td><td style="text-align:left;">寒证（阳虚寒凝）</td></tr><tr><td style="text-align:left;"><strong>相关</strong></td><td style="text-align:left;">⭐ <strong>很可能迟脉</strong>（阳虚）</td></tr><tr><td style="text-align:left;"><strong>方剂参考</strong></td><td style="text-align:left;">四逆汤、理中汤</td></tr></tbody></table><h3 id="数脉" tabindex="-1">数脉 <a class="header-anchor" href="#数脉" aria-label="Permalink to &quot;数脉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉象</strong></td><td style="text-align:left;">一息五至以上（&gt;90次/分）</td></tr><tr><td style="text-align:left;"><strong>主病</strong></td><td style="text-align:left;">热证、虚阳上浮</td></tr><tr><td style="text-align:left;"><strong>相关</strong></td><td style="text-align:left;">如果数而无力→虚阳上越</td></tr><tr><td style="text-align:left;"><strong>方剂参考</strong></td><td style="text-align:left;">数而有力→白虎汤；数而无力→潜阳丹</td></tr></tbody></table><h3 id="弦脉" tabindex="-1">弦脉 <a class="header-anchor" href="#弦脉" aria-label="Permalink to &quot;弦脉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉象</strong></td><td style="text-align:left;">端直以长，如按琴弦</td></tr><tr><td style="text-align:left;"><strong>主病</strong></td><td style="text-align:left;">肝郁、痛证、痰饮</td></tr><tr><td style="text-align:left;"><strong>相关</strong></td><td style="text-align:left;">⭐ <strong>很可能弦脉</strong>（肝郁）</td></tr><tr><td style="text-align:left;"><strong>方剂参考</strong></td><td style="text-align:left;">弦细→四逆散；弦滑→温胆汤</td></tr></tbody></table><h3 id="细脉" tabindex="-1">细脉 <a class="header-anchor" href="#细脉" aria-label="Permalink to &quot;细脉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉象</strong></td><td style="text-align:left;">脉细如丝，应指明显</td></tr><tr><td style="text-align:left;"><strong>主病</strong></td><td style="text-align:left;">气血两虚</td></tr><tr><td style="text-align:left;"><strong>相关</strong></td><td style="text-align:left;">⭐ <strong>很可能细脉</strong>（血虚）</td></tr><tr><td style="text-align:left;"><strong>方剂参考</strong></td><td style="text-align:left;">四物汤、炙甘草汤</td></tr></tbody></table><h3 id="滑脉" tabindex="-1">滑脉 <a class="header-anchor" href="#滑脉" aria-label="Permalink to &quot;滑脉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉象</strong></td><td style="text-align:left;">往来流利，应指圆滑</td></tr><tr><td style="text-align:left;"><strong>主病</strong></td><td style="text-align:left;">痰饮、食积、实热、妊娠</td></tr><tr><td style="text-align:left;"><strong>方剂参考</strong></td><td style="text-align:left;">二陈汤（痰）、白虎汤（热）</td></tr></tbody></table><h3 id="涩脉" tabindex="-1">涩脉 <a class="header-anchor" href="#涩脉" aria-label="Permalink to &quot;涩脉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉象</strong></td><td style="text-align:left;">往来艰涩，如轻刀刮竹</td></tr><tr><td style="text-align:left;"><strong>主病</strong></td><td style="text-align:left;">气滞血瘀、精亏血少</td></tr><tr><td style="text-align:left;"><strong>方剂参考</strong></td><td style="text-align:left;">血府逐瘀汤（实）、四物汤（虚）</td></tr></tbody></table><h3 id="濡脉" tabindex="-1">濡脉 <a class="header-anchor" href="#濡脉" aria-label="Permalink to &quot;濡脉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉象</strong></td><td style="text-align:left;">浮而细软，如绵在水</td></tr><tr><td style="text-align:left;"><strong>主病</strong></td><td style="text-align:left;">湿困脾胃、气虚</td></tr><tr><td style="text-align:left;"><strong>方剂参考</strong></td><td style="text-align:left;">黄芽汤、参苓白术散</td></tr></tbody></table><h3 id="微脉" tabindex="-1">微脉 <a class="header-anchor" href="#微脉" aria-label="Permalink to &quot;微脉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉象</strong></td><td style="text-align:left;">极细极软，似有似无</td></tr><tr><td style="text-align:left;"><strong>主病</strong></td><td style="text-align:left;">亡阳、气血大虚</td></tr><tr><td style="text-align:left;"><strong>方剂参考</strong></td><td style="text-align:left;">四逆加人参汤、独参汤</td></tr></tbody></table><hr><h2 id="三、脉证合参-关键原则" tabindex="-1">三、脉证合参（关键原则） <a class="header-anchor" href="#三、脉证合参-关键原则" aria-label="Permalink to &quot;三、脉证合参（关键原则）&quot;">​</a></h2><blockquote><p><strong>王叔和：「脉证相参，乃可万全。」</strong></p></blockquote><h3 id="舍脉从证" tabindex="-1">舍脉从证 <a class="header-anchor" href="#舍脉从证" aria-label="Permalink to &quot;舍脉从证&quot;">​</a></h3><p>当脉象与症状矛盾时，以症状为准。例如：</p><ul><li>症状：大热大渴（看似热证）</li><li>脉象：沉迟（寒证）</li><li><strong>结论</strong>：真寒假热，舍脉从证 → 四逆汤</li></ul><h3 id="舍证从脉" tabindex="-1">舍证从脉 <a class="header-anchor" href="#舍证从脉" aria-label="Permalink to &quot;舍证从脉&quot;">​</a></h3><p>当症状不典型而脉象典型时，以脉象为准。例如：</p><ul><li>症状：无明显不适</li><li>脉象：结代（心律不齐）</li><li><strong>结论</strong>：舍证从脉 → 炙甘草汤</li></ul><hr><h2 id="四、不同类型患者脉象推测" tabindex="-1">四、不同类型患者脉象推测 <a class="header-anchor" href="#四、不同类型患者脉象推测" aria-label="Permalink to &quot;四、不同类型患者脉象推测&quot;">​</a></h2><h3 id="患者-男-根据症状推测" tabindex="-1">患者（男）（根据症状推测） <a class="header-anchor" href="#患者-男-根据症状推测" aria-label="Permalink to &quot;患者（男）（根据症状推测）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">切脉项目</th><th style="text-align:left;">推测</th><th style="text-align:left;">依据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉位</strong></td><td style="text-align:left;">沉取明显（沉脉）</td><td style="text-align:left;">水寒土湿，病在里</td></tr><tr><td style="text-align:left;"><strong>脉率</strong></td><td style="text-align:left;">可能偏慢（迟脉）</td><td style="text-align:left;">阳虚</td></tr><tr><td style="text-align:left;"><strong>脉形</strong></td><td style="text-align:left;">可能弦或涩</td><td style="text-align:left;">肝郁+瘀血</td></tr><tr><td style="text-align:left;"><strong>总体</strong></td><td style="text-align:left;"><strong>沉弦细或沉迟</strong></td><td style="text-align:left;">少阴寒化+肝郁</td></tr></tbody></table><h3 id="患者-女-根据症状推测" tabindex="-1">患者（女）（根据症状推测） <a class="header-anchor" href="#患者-女-根据症状推测" aria-label="Permalink to &quot;患者（女）（根据症状推测）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">切脉项目</th><th style="text-align:left;">推测</th><th style="text-align:left;">依据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脉位</strong></td><td style="text-align:left;">可能偏沉</td><td style="text-align:left;">中气虚</td></tr><tr><td style="text-align:left;"><strong>脉率</strong></td><td style="text-align:left;">可能偏数</td><td style="text-align:left;">虚火浮越</td></tr><tr><td style="text-align:left;"><strong>脉形</strong></td><td style="text-align:left;">细或弦细</td><td style="text-align:left;">血虚+肝郁</td></tr><tr><td style="text-align:left;"><strong>总体</strong></td><td style="text-align:left;"><strong>沉细数或弦细数</strong></td><td style="text-align:left;">中虚血亏+郁火</td></tr></tbody></table><hr><h2 id="五、脉象与方剂快速对应" tabindex="-1">五、脉象与方剂快速对应 <a class="header-anchor" href="#五、脉象与方剂快速对应" aria-label="Permalink to &quot;五、脉象与方剂快速对应&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">脉象</th><th style="text-align:left;">快速选方</th></tr></thead><tbody><tr><td style="text-align:left;">浮紧</td><td style="text-align:left;">麻黄汤</td></tr><tr><td style="text-align:left;">浮缓</td><td style="text-align:left;">桂枝汤</td></tr><tr><td style="text-align:left;">浮数</td><td style="text-align:left;">银翘散</td></tr><tr><td style="text-align:left;">沉迟</td><td style="text-align:left;">四逆汤</td></tr><tr><td style="text-align:left;">沉弦</td><td style="text-align:left;">四逆散/柴胡汤</td></tr><tr><td style="text-align:left;">沉细</td><td style="text-align:left;">四物汤/炙甘草汤</td></tr><tr><td style="text-align:left;">弦滑</td><td style="text-align:left;">温胆汤</td></tr><tr><td style="text-align:left;">弦数</td><td style="text-align:left;">丹栀逍遥散</td></tr><tr><td style="text-align:left;">滑数</td><td style="text-align:left;">白虎汤</td></tr><tr><td style="text-align:left;">涩</td><td style="text-align:left;">血府逐瘀汤/四物汤</td></tr><tr><td style="text-align:left;">濡</td><td style="text-align:left;">黄芽汤/参苓白术散</td></tr><tr><td style="text-align:left;">微</td><td style="text-align:left;">四逆加人参汤</td></tr></tbody></table><hr><p><em>本索引为精简框架版。脉诊必须经过长期的&quot;指下练习&quot;才能掌握，建议结合脉诊仪或当面师承学习。</em></p>',48)])])}const y=e(r,[["render",n]]);export{f as __pageData,y as default};
